import React, { useState, useCallback, useMemo } from 'react';
import PropTypes from 'prop-types';
import image from '../../../images/quizImages/2.svg';
import InputField from '../InputField';
import Buttons from '../Buttons';
import ProgressBar from '../ProgressBar';
import styles from './screentwo.css'; // Assuming you are using CSS modules

const ScreenTwo = ({ screen, nmscreen, formData, handleInputChange }) => {
  const [errors, setErrors] = useState({});

  const validateForm = useCallback(() => {
    const newErrors = {};
    if (!formData.name) newErrors.name = 'Name is required';
    if (!formData.email) newErrors.email = 'Email is required';
    if (!formData.phone) newErrors.phone = 'Phone number is required';
    if (!formData.gender) newErrors.gender = 'Gender is required';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [formData]);

  const handleNextScreen = useCallback(() => {
    if (validateForm()) {
      screen('screen3');
    }
  }, [validateForm, screen]);

  const getInputClass = useCallback(
    (field) => (errors[field] ? styles.invalid : ''),
    [errors]
  );

  return (
    <div id="screen2" className={styles.screen}>
      <h1 className={styles.title}>
        First we are going to need some of your personal information
      </h1>
      <p className={styles.message}>
        Don’t worry everything will be kept anonymous and it is in safe hands!
      </p>
      <div className={styles.contactDetails}>
        <InputField
          className={`${styles.name} ${getInputClass('name')}`}
          type="text"
          name="Name"
          value={formData.name}
          placeholder="ex. Manuel Aguires"
          onChange={(e) => handleInputChange('name', e.target.value)}
        />
        {errors.name && <p className={styles.errorMessage}>{errors.name}</p>}

        <InputField
          className={`${styles.mail} ${getInputClass('email')}`}
          type="email"
          name="Email"
          value={formData.email}
          placeholder="ex. youremail@gmail.com"
          onChange={(e) => handleInputChange('email', e.target.value)}
        />
        {errors.email && <p className={styles.errorMessage}>{errors.email}</p>}

        <InputField
          className={`${styles.phoneNumber} ${getInputClass('phone')}`}
          type="tel"
          name="PhoneNumber"
          value={formData.phone}
          placeholder="ex. +(34) 6548752146"
          onChange={(e) => handleInputChange('phone', e.target.value)}
        />
        {errors.phone && <p className={styles.errorMessage}>{errors.phone}</p>}

        <InputField
          className={`${styles.gender} ${getInputClass('gender')}`}
          type="text"
          name="Gender"
          value={formData.gender}
          placeholder="Male / Female"
          onChange={(e) => handleInputChange('gender', e.target.value)}
        />
        {errors.gender && <p className={styles.errorMessage}>{errors.gender}</p>}
      </div>
      <Buttons
        changeScreen={screen}
        back={'screen1'}
        next={handleNextScreen}
        nb={1}
        nn={3}
      />
      <div className={styles.graph}>
        <img src={image} alt="Visual representation" />
      </div>
    </div>
  );
};

ScreenTwo.propTypes = {
  screen: PropTypes.func.isRequired,
  nmscreen: PropTypes.string,
  formData: PropTypes.shape({
    name: PropTypes.string,
    email: PropTypes.string,
    phone: PropTypes.string,
    gender: PropTypes.string,
  }).isRequired,
  handleInputChange: PropTypes.func.isRequired,
};

export default ScreenTwo;
